/**
 * Context Assembly with Image Markers
 *
 * Formats retrieved documents with citation metadata,
 * tracks image markers.
 */

const items = this.getInputData();
const rerankedResults = items[0].json.results || [];
const userQuery = items[0].json.userQuery;

// Build citation-formatted context and track images
let contextBlocks = [];
let imageMap = {};

let i = 0;
for (const result of rerankedResults) {
  const meta = result.metadata;
  let citation = '';
  if (meta.contentType === 'pdf' && meta.page) {
    citation = `[Quelle: ${meta.source}, Seite: ${meta.page}]`;
  } else if (meta.contentType === 'spreadsheet' && meta.sheetName) {
    citation = `[Quelle: ${meta.source}, Sheet: ${meta.sheetName}, Zeile: ${meta.row}]`;
  } else if (meta.paragraph) {
    citation = `[Quelle: ${meta.source}, Paragraph: ${meta.paragraph}]`;
  } else {
    citation = `[Quelle: ${meta.source}]`;
  }

  const hasImage = !!meta.imageId;
  let imageInstruction = '';
  if (hasImage) {
    imageMap[meta.imageId] = {
      citation: citation,
      page: meta.page,
      fileName: meta.fileName,
      fileHash: meta.fileHash
    };
    imageInstruction = `\n⚠️ THIS CHUNK HAS AN ASSOCIATED IMAGE. Image marker: [IMAGE:${meta.imageId}]. Add that to the response`;
  }

  const block = `[ID: ${i}] ${citation}\nContent: ${result.text}${imageInstruction}\n`;
  contextBlocks.push(block);
  i++;
}


const assembledContext = contextBlocks.join('\n---\n\n');

const imageIds = Object.keys(imageMap);
let imageInstructions = '';
if (imageIds.length > 0) {
  imageInstructions = `\n\nIMAGE PLACEMENT RULES:\n`
    + `- Some context chunks have associated images marked with [IMAGE:uuid].\n`
    + `- When you use information from a chunk that has an image, you MUST place the exact image marker tag on its OWN line.\n`
    + `- Place the image marker IMMEDIATELY AFTER the sentence or paragraph that describes what the image shows.\n`
    + `- Do NOT place all images at the end.\n`
    + `- Do NOT modify the image marker format.\n`
    + `- If a chunk has an image but you don't use that chunk's content, do NOT include its image marker.\n`
    + `\nAvailable image markers:\n`
    + imageIds.map(id => `- [IMAGE:${id}] (from ${imageMap[id].citation})`).join('\n');
}

// Context metadata
const sources = rerankedResults.map(r => ({
  source: r.metadata.source,
  page: r.metadata.page,
  score: r.score
}));

return [{
  json: {
    ...items[0].json,
    assembledContext: assembledContext,
    imageIds: imageIds,
    imageMap: imageMap,
    imageInstructions: imageInstructions,
    userQuery: userQuery,
    searchPerformed: true,
    contextMetadata: {
      totalChunks: rerankedResults.length,
      sources: sources,
    }
  }
}];

const crypto = require('crypto');

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryPropertyName = 'data';

  try {
    if (!item.binary || !item.binary[binaryPropertyName]) {
      continue;
    }

    const fileBuffer = await this.helpers.getBinaryDataBuffer(i, binaryPropertyName);
    const fileHash = crypto.createHash('md5').update(fileBuffer).digest('hex');
    const binaryData = item.binary[binaryPropertyName];
    const fileName = binaryData.fileName || 'unknown';

    results.push({
      json: {
        fileName: fileName,
        fileHash: fileHash,
        fileSize: binaryData.fileSize || fileBuffer.length,
        mimeType: binaryData.mimeType,
        path: binaryData.directory + '/' + fileName,
        extension: binaryData.fileExtension || fileName.split('.').pop().toLowerCase()
      }
    });
  } catch (error) {
    console.error(`Error processing item ${i}: ${error.message}`);
  }
}

return results;

