const dbRegistry = $('Table DB Lookup').all().map(i => i.json);

const results = [];
const dbMap = new Map();
dbRegistry.forEach(record => { dbMap.set(record.file_path, record); });

for (const file of fileScan) {
  const path = file.path;
  const dbRecord = dbMap.get(path);
  const normalizedItem = {
    fileName: file.fileName ?? path.split('/').pop(),
    fileHash: file.fileHash,
    fileSize: file.fileSize,
    mimeType: file.mimeType,
    path: file.path,
    extension: file.extension
  };

  if (!dbRecord) {
    results.push({ json: { type: 'new', item: normalizedItem } });
  } else {
    dbMap.delete(path);
    if (file.fileHash === dbRecord.file_hash) {
      results.push({ json: { type: 'unchanged', item: normalizedItem } });
    } else {
      results.push({ json: { type: 'modified', item: normalizedItem } });
    }
  }
}

for (const [path, record] of dbMap) {
  if (!path || path === '__setup_test__') continue;
  // Only process table file extensions
  const ext = (path.split('.').pop() || '').toLowerCase();
  if (!['csv', 'tsv', 'xlsx', 'xls', 'ods'].includes(ext)) continue;
  const fileName = typeof path === 'string' ? path.split('/').pop() : null;
  results.push({
    json: {
      type: 'deleted',
      item: {
        fileName,
        fileHash: record.file_hash ?? null,
        fileSize: record.file_size ?? null,
        mimeType: record.content_type ?? null,
        path: record.file_path ?? null,
        extension: ext
      }
    }
  });
}

return results;

